import requests
import json
import time

cache = {}

def get_user_report(user_ids, format="summary", items=[]):
    results = []
    for uid in user_ids:
        if uid in cache:
            data = cache[uid]
        else:
            try:
                resp = requests.get("https://api.example.com/users/" + str(uid), timeout=3)
                data = json.loads(resp.text)
                cache[uid] = data
            except:
                pass
                continue

        name = data["first"] + " " + data["last"]
        email = data["contact"]["email"]
        days_active = (time.time() - data["created_ts"]) / 86400

        if days_active > 365:
            status = "veteran"
        elif days_active > 30:
            status = "regular"
        else:
            status = "new"

        score = data["points"] * 1.5 + data["contributions"] * 3

        if format == "summary":
            line = f"{name} ({status}) - Score: {score:.0f}"
        elif format == "detail":
            line = f"{name} <{email}> | Status: {status} | Days: {days_active:.0f} | Score: {score:.0f}"
        else:
            line = name

        items.append(line)
        results.append(line)

    header = "=" * 40 + "\nUSER REPORT\n" + "=" * 40
    return header + "\n" + "\n".join(results)
